#!/usr/bin/env bash

### File generates info that cannot be accessed during build time by Nix

_USERINFO=$(
    cat <<'EOF_nix' | awk -v name="$(id -un)" -v home="$HOME" -v uid="$(id -u)" -v appleID="$(defaults read MobileMeAccounts Accounts >/dev/null 2>&1 && echo "true" || echo "false")" '{
        gsub(/__NAME__/, name)
        gsub(/__HOME__/, home)
        gsub(/__UID__/, uid)
        gsub(/__APPLEID__/, appleID)
        print
    }'
## This file is autogenerated - DO NOT EDIT
{
  name = "__NAME__";
  home = "__HOME__";
  uid = __UID__;
  hasAppleID = __APPLEID__;
}
# vim: set ts=2 sw=2 et ft=nix:
EOF_nix
)
mkdir -p ~/.config/nix
_USERNIX=~/.config/nix/userinfo.nix

if [[ -f $_USERNIX ]] && diff $_USERNIX <(echo "$_USERINFO") >/dev/null; then
    exit 0
fi

echo "Auto-generating $_USERNIX file"
echo "$_USERINFO" >$_USERNIX
